<!-- Child: FAQComponent.vue -->
<template>
  <div class="faq-container">
    <div class="modal-title">
      <h2> FAQ </h2>
    </div>

    <!-- We use the current rotation data for the HelpCard -->
    <HelpCardComponent
        :cardTitle="currentRotation.q"
        :cardMessage="currentRotation.a"
    />

    <!-- Static list below (optional) -->
    <div v-for="(item, index) in faqData" :key="index">
        <!-- your existing list code -->
    </div>
  </div>
</template>

<script>
import HelpCardComponent from '@/components/contact/HelpCardComponent.vue';

export default {
  components: { HelpCardComponent },
  props: {
    faqData: {
      type: Array,
      required: true
    }
  },
  data() {
    return {
      activeIndex: 0,
      timer: null
    };
  },
  computed: {
    // This dynamically returns the Q&A based on the activeIndex
    currentRotation() {
      if (this.faqData && this.faqData.length > 0) {
        return this.faqData[this.activeIndex];
      }
      return { q: "Loading...", a: "..." };
    }
  },
  methods: {
    startRotation() {
      this.timer = setInterval(() => {
        // Increment index, or reset to 0 if at the end of the array
        this.activeIndex = (this.activeIndex + 1) % this.faqData.length;
      }, 20000); // 30,000ms = 30s
    }
  },
  mounted() {
    this.startRotation();
  },
  beforeUnmount() {
    // IMPORTANT: Stop the timer if the user leaves the page to prevent memory leaks
    clearInterval(this.timer);
  }
}
</script>
