<template>
<div class="contact-view">

    <div class="empty-cell">
        <!-- to accomodate floating nav bar -->
    </div>
    
    <div class="grid-child call-cell">
        <PhoneComponent
        :dataDictionary="phoneData"
        />
        <HelperCard
        :cardTitle="phoneData.cardTitle"
        :cardMessage="phoneData.cardMessage"
        />
        <!-- floating call button -->
    </div>

    <div class="grid-child socials-cell">
        <SocialsComponent
        :socials="{
            linkedin: getSocialsUrl('linkedin'),
            github: getSocialsUrl('github'),
            instagram: getSocialsUrl('instagram'),
            facebook: getSocialsUrl('facebook')
        }"
        />
    </div>

    <div class="grid-child faq-cell">
        <FAQComponent
            :faqData="faqData"
            cardTitle="FAQ Help" 
            cardMessage="Find answers to common questions here."
        />

    </div>

    <div class="grid-child appointment-cell">
        <AppointmentComponent
        :dataDictionary="appointmentData.dataDictionary"
        />
        <HelperCard
        :cardTitle="appointmentData.dataDictionary.cardTitle"
        :cardMessage="appointmentData.dataDictionary.cardMessage"
        />
    </div>

</div>
</template>

<script>
import home from '@/data/home.json';
import helperdata from '@/data/contact.json';
import PhoneComponent from '@/components/global/PhoneChild.vue';
import HelperCard from '@/components/contact/HelpCardComponent.vue';
import AppointmentComponent from '@/components/global/AppointmentChild.vue';
import SocialsComponent from '@/components/contact/socialsComponent.vue';
import FAQComponent from '@/components/contact/FAQComponent.vue';
export default {
  name: "ContactView",
  components: {
    PhoneComponent,
    HelperCard,
    AppointmentComponent,
    SocialsComponent,
    FAQComponent
  },
  data() {
    return {
        "phoneData": {
            title: home.mobile.title.charAt(0).toUpperCase() + home.mobile.title.slice(1),
            number: home.mobile.number,
            cardTitle: helperdata.callHelpCard.title,
            cardMessage: helperdata.callHelpCard.message,
        },
        "appointmentData": {
            "dataDictionary": {
                title: home.appointment.title.charAt(0).toUpperCase() + home.appointment.title.slice(1),
                meetingTypes: home.appointment.meeting_types,
                cardTitle: helperdata.appointmentHelpCard.title,
                cardMessage: helperdata.appointmentHelpCard.message,
            },
        },
        faqData: helperdata.faq
    }
  },
  methods: {
   getSocialsUrl(type) {
    const social = home.contact.socials.find(s =>
        s.type.toLowerCase() === type.toLowerCase()
    );
    console.log(social);
    return social ? social.details : "unavailable";
}

    }
}
</script>